let h=0,l=0;const n=document.getElementById("compassNeedle"),s=document.getElementById("splash");window.addEventListener("load",()=>{setTimeout(()=>{s.style.opacity="0";setTimeout(()=>s.remove(),500)},800)});setInterval(()=>{h=(h+2)%360;const e=Math.abs(h-130),t=e>180?360-e:e;n.style.transform=`translate(-50%,-85%) rotate(${h}deg)`;Math.abs(h-l)>5?n.classList.add("motion-blur"):n.classList.remove("motion-blur");l=h},80);
